effect.shader:
void main() {
    vec2 image_size = getTexSize(inputImg.size);
    vec2 texelSize = 1.0 / image_size;
    vec2 relCenter = vec2(0.5 + centerPoint.x/500., 0.5 - centerPoint.y/500.);
    vec2 center = (vec4(relCenter,0.0,1.0) * acLayerToScreen).xy;
    vec2 v = acScreenNorm.st - center;
    v.y *= image_size.y / image_size.x;
    float r = length(v);
    float d = 6.283185*r;
    float l = d*angle/360.0;
    float a = angle * 0.0174533;
    float amin = a/2.0 + (a*bias/2.0);
    float speed = l/texelSize.x;
    int nSamples = int(clamp(speed, 1.01, 100.01));
    vec4 originalColor = texture2DCv(inputImg.texture,acScreenNorm.st);
    vec4 outColor = originalColor;
    outColor.rgb = outColor.a > 0.0 ? outColor.rgb/outColor.a : outColor.rgb;
    for(int i=1; i<nSamples; i++ ) {
        float sampleAngle = -amin + a * float(i)/float(nSamples);
        float s = sin(sampleAngle);
        float cs = cos(sampleAngle);
        mat2 rot = mat2(cs, -s, s, cs);
        vec2 temp = v*rot;
        temp.y = temp.y * image_size.x / image_size.y;

        vec4 c = texture2DCv(inputImg.texture, center + temp);

        float r;
        float g;
        float b;
        float a;
        if( rmode == 0 ) {
            r = min(outColor.r,c.r);
        } else if( rmode == 1 ) {
            r = max(outColor.r,c.r);
        } else if( rmode == 3 ) {
            r = outColor.r + c.r;
        } else {
            r = outColor.r;
        }
        if( gmode == 0 ) {
            g = min(outColor.g,c.g);
        } else if( gmode == 1 ) {
            g = max(outColor.g,c.g);
        } else if( gmode == 3 ) {
            g = outColor.g + c.g;
        } else {
            g = outColor.g;
        }
        if( bmode == 0 ) {
            b = min(outColor.b,c.b);
        } else if( bmode == 1 ) {
            b = max(outColor.b,c.b);
        } else if( bmode == 3 ) {
            b = outColor.b + c.b;
        } else {
            b = outColor.b;
        }
        if( amode == 0 ) {
            a = min(outColor.a,c.a);
        } else if( amode == 1 ) {
            a = max(outColor.a,c.a);
        } else if( amode == 3 ) {
            a = outColor.a + c.a;
        } else {
            a = outColor.a;
        }
        outColor = vec4(r,g,b,a);

    }
    outColor = outColor / vec4(
        rmode == 3 ? float(nSamples) : 1.0,
        gmode == 3 ? float(nSamples) : 1.0,
        bmode == 3 ? float(nSamples) : 1.0,
        amode == 3 ? float(nSamples) : 1.0
    );
    outColor.rgb *= outColor.a;
    gl_FragColor = mix(originalColor,outColor,alpha);
}
